public int active()
{

    int ret = next active();



    boolean freeze = ETGCanadaParametersHelper1::isExchangeRateFrozen();

    FormRun formRun = this.formRun();
    FormDesign design = formRun.design();



    FormControl exchRateCtrl =design.controlName(identifierStr(fieldExchRate));
    FormControl repExchRateCtrl =design.controlName(identifierStr(ReportingfieldExchRate));
    FormControl lineExchRateCtrl =design.controlName(identifierStr(LedgerJournalTrans_ExchRate));

    FormDataObject fdoExchRate  =this.object(fieldNum(LedgerJournalTrans,ExchRate));
    FormDataObject fdoReportingFieldExchRate=this.object(fieldNum(LedgerJournalTrans,ReportingCurrencyExchRate));


    if (!freeze)
    {
        exchRateCtrl.allowEdit(true);
        repExchRateCtrl.allowEdit(true);
        lineExchRateCtrl.allowEdit(true);
        fdoExchRate.allowEdit(true);
        fdoReportingFieldExchRate.allowEdit(true);

    }
    else
    {
        exchRateCtrl.allowEdit(false);
        repExchRateCtrl.allowEdit(false);
        lineExchRateCtrl.allowEdit(false);
        fdoExchRate.allowEdit(false);
        fdoReportingFieldExchRate.allowEdit(false);

    }
    return ret;

}
